import os, glob, yaml, json

# Read all existing articles' frontmatter
articles = {}
for d in ['wiki/concepts', 'wiki/connections']:
    for fpath in glob.glob(os.path.join(d, '*.md')):
        slug = os.path.basename(fpath).replace('.md', '')
        with open(fpath) as f:
            content = f.read()
        fm = {}
        if content.startswith('---'):
            parts = content.split('---', 2)
            if len(parts) >= 3:
                try:
                    fm = yaml.safe_load(parts[1]) or {}
                except:
                    pass
        articles[slug] = {
            'type': 'concept' if 'concepts' in d else 'connection',
            'title': fm.get('title', slug),
            'confidence': fm.get('confidence', 'low'),
            'evidence_count': fm.get('evidence_count', 0),
            'phase': fm.get('phase', []),
            'category': fm.get('category', ''),
            'tags': fm.get('tags', []),
        }

for slug, info in sorted(articles.items()):
    print(f'{info[\"type\"]:10} | {info[\"confidence\"]:6} | {info[\"evidence_count\"]:3} | {slug}')
" 2>&1", "timeout": 30}
